    ["Status Tracking Bars"] = "Barras de rastreamento de status",
    ["Status Tracking Bars (Req. Reload)"] = "Barras de rastreamento de status (Req. Recarregar)",
    ["Status bar texture used to fill the prey tracker bar."] = "Textura da barra de status usada para preencher a barra do rastreador de presas.",
    ["Statusbar texture used for both skyriding bars. Supports any extra media packages you have available."] = "Textura da barra de status usada para ambas as barras de skyriding. Suporta quaisquer pacotes de mídia extras que você tiver disponível.",
    ["Statusbar texture used for the XP fill. Supports any extra media packages you have available."] = "Textura da barra de status usada para o preenchimento de XP. Suporta quaisquer pacotes de mídia extras que você tiver disponível.",
    ["Statusbar texture used for the absorb overlay. Stripes or patterned textures make absorbs easier to read at a glance."] = "Textura da barra de status usada para a sobreposição de absorção. Texturas listradas ou padronizadas facilitam a leitura das absorções à primeira vista.",
    ["Statusbar texture used for the bar fill."] = "Textura da barra de status usada para o preenchimento da barra.",
    ["Statusbar texture used for the health bar. Supports SharedMedia textures."] = "Textura da barra de status usada para a barra de saúde. Suporta texturas SharedMedia.",
    ["Statusbar texture used for the health bar. Supports SharedMedia."] = "Textura da barra de status usada para a barra de saúde. Suporta SharedMedia.",
    ["Statusbar texture used for the power fill."] = "Textura da barra de status usada para o preenchimento de poder.",
    ["Statusbar texture used to fill the castbar. Supports SharedMedia."] = "Textura da barra de status usada para preencher a barra de conjuração. Suporta SharedMedia.",
    ["Stop the combat-end profiler and unwrap functions."] = "Para de perfilador do fim do combate e desembrulha as funções.",
    ["Store separate entry lists per specialization, so each spec shows a different set of tracked spells. The current list is swapped in on spec change."] = "Armazena listas separadas de entradas por especialização, para que cada spec mostre um conjunto diferente de feitiços rastreados. A lista atual é trocada ao mudar de spec.",
    ["Store text settings separately per specialization."] = "Armazena as configurações de texto separadamente por especialização.",
    ["Store whispers"] = "Armazenar sussurros",
    ["Stored but not joined"] = "Armazenado, mas não conectado",
    ["Stored exclusion for '%s'. Disable to remove from the persistent exclusion set."] = "Exclusão armazenada para '%s'. Desative para remover do conjunto persistente de exclusões.",
    ["Strength"] = "Força",
    ["Stretch bars to match the width of the frame they anchor to (e.g. the player frame)."] = "Estende as barras para coincidir com a largura do quadro ao qual estão ancoradas (por exemplo, o quadro do jogador).",
    ["Stretch the bar to match the frame size."] = "Estica a barra para coincidir com o tamanho do quadro.",
    ["Strip the guild name line from player tooltips."] = "Remove a linha do nome da guilda das dicas do jogador.",
    ["Strip the realm name from cross-realm player tooltips for a cleaner display."] = "Remove o nome do reino das dicas de jogadores de outros reinos para uma exibição mais limpa.",
    ["Stroke style of the ring that surrounds the reticle."] = "Estilo do traço do anel que circunda o retículo.",
    ["Subsystems"] = "Subsistemas",
    ["Subtle Pulse"] = "Pulso sutil",
    ["Summon Pending"] = "Invocação pendente",
    ["Support"] = "Suporte",
    ["Supports SharedMedia textures. Install the SharedMedia addon to add your own."] = "Suporta texturas SharedMedia. Instale o addon SharedMedia para adicionar as suas próprias.",
    ["Suppress all cooldown effects (swipe, overlay, flash) for this container, even on Blizzard-managed elements driven by the same icons."] = "Suprime todos os efeitos de recarga (varredura, sobreposição, flash) para este contêiner, mesmo nos elementos gerenciados pelo Blizzard acionados pelos mesmos ícones.",
    ["Suppress all tooltips while you're in combat. Use the modifier key below to force-show them when needed."] = "Suprime todas as dicas enquanto você estiver em combate. Use a tecla modificadora abaixo para forçá-las a aparecer quando necessário.",
    ["Suppress entitlement and recruit-a-friend delivery toast notifications."] = "Suprime notificações toast de entrega de recrutamento e amigo recruta.",
    ["Suppress general event toast popups, often triggered by campaign progress or housing updates."] = "Suprime pop-ups toast de eventos gerais, frequentemente acionados por progresso de campanha ou atualizações de moradia.",
    ["Suppress the blocking static popups that appear for housing-related confirmations."] = "Suprime os pop-ups estáticos bloqueadores que aparecem para confirmações relacionadas à moradia.",
    ["Suppress the blocking static popups that appear for talent-related confirmations."] = "Suprime os pop-ups estáticos bloqueadores que aparecem para confirmações relacionadas a talentos.",
    ["Suppress the glow animation on every microbutton (collections, achievements, etc.) when new items are detected."] = "Suprime a animação de brilho em cada microbotão (coleções, conquistas etc.) quando novos itens são detectados.",
    ["Suppress the pulsing reminder on the talent microbutton that appears when unspent points are available."] = "Suprime o lembrete pulsante no microbotão de talentos que aparece quando há pontos não gastos disponíveis.",
    ["Suppress the red error messages printed above the action bar, such as Not Enough Mana or Spell Not Ready."] = "Suprime as mensagens de erro vermelhas impressas acima da barra de ação, como Mana Insuficiente ou Feitiço Não Pronto.",
    ["Suppress the toast that pops when you acquire a new cosmetic item."] = "Suprime o toast que aparece quando você adquire um novo item cosmético.",
    ["Suppress the toast that pops when you learn a new battle pet."] = "Suprime o toast que aparece quando você aprende um novo mascote de batalha.",
    ["Suppress the toast that pops when you learn a new mount."] = "Suprime o toast que aparece quando você aprende uma nova montaria.",
    ["Suppress the toast that pops when you learn a new toy."] = "Suprime o toast que aparece quando você aprende um novo brinquedo.",
    ["Suppress the tutorial help tip callouts that Blizzard shows near talent and spellbook buttons."] = "Suprime as chamadas de ajuda tutorial que o Blizzard mostra perto dos botões de talentos e do livro de feitiços.",
    ["Suppress the yellow info messages printed above the action bar, such as quest objective progress updates."] = "Suprime as mensagens de informação amarelas impressas acima da barra de ação, como atualizações de progresso de objetivo de missão.",
    ["Suppress warband scene notification toasts."] = "Suprime toasts de notificação de cena de warband.",
    ["Swap the vigor bar color while Thrill of the Skies is active so the buff state is obvious."] = "Troca a cor da barra de vigor enquanto Thrill of the Skies estiver ativo para deixar o estado do buff evidente.",
    ["Swap to Primary Position"] = "Trocar para posição primária",
    ["Sweep the GCD during instant melee swings, not just during spell casts."] = "Varre o GCD durante ataques corpo a corpo instantâneos, não apenas durante conjurações de feitiços.",
    ["Swipe Custom Color"] = "Cor personalizada da varredura",
