    ["This bar has no entries for your current spec"] = "Esta barra não tem entradas para sua especialização atual",
    ["This cannot be undone."] = "Isto não pode ser desfeito.",
    ["This cannot be undone. Other characters' saved files are only loaded by WoW when that character logs in, so they will be wiped at their next login."] = "Isto não pode ser desfeito. Os arquivos salvos de outros personagens só são carregados pelo WoW quando aquele personagem entra no jogo, então serão apagados no próximo login dele.",
    ["This cannot be undone. The cache rebuilds on the next guild bank visit."] = "Isto não pode ser desfeito. O cache é reconstruído na próxima visita ao banco da guilda.",
    ["This cannot be undone. The cache rebuilds the next time that character logs in."] = "Isto não pode ser desfeito. O cache é reconstruído na próxima vez que aquele personagem entrar no jogo.",
    ["This change requires a reload to take effect."] = "Esta alteração requer recarregamento para ter efeito.",
