    ["Vertical pixel offset from the anchor point."] = "Deslocamento vertical em pixels a partir do ponto de âncora.",
    ["Vertical pixel offset from the anchor point. Positive values move the frame up, negative values move it down."] = "Deslocamento vertical em pixels a partir do ponto de âncora. Valores positivos movem o quadro para cima, negativos o movem para baixo.",
    ["Vertical pixel offset from the anchor."] = "Deslocamento vertical em pixels a partir da âncora.",
    ["Vertical pixel offset from the auto-attach anchor (or from its manual position when Auto Attach is off)."] = "Deslocamento vertical em pixels a partir da âncora de autoanexação (ou da posição manual quando Auto Anexar estiver desativado).",
    ["Vertical pixel offset from the auto-attach anchor."] = "Deslocamento vertical em pixels a partir da âncora de autoanexação.",
    ["Vertical pixel offset from the target anchor point."] = "Deslocamento vertical em pixels a partir do ponto de âncora do alvo.",
    ["Vertical pixel offset of the combat text from the screen center."] = "Deslocamento vertical em pixels do texto de combate a partir do centro da tela.",
    ["Vertical pixel offset of the distance text from its anchor."] = "Deslocamento vertical em pixels do texto de distância a partir da sua âncora.",
    ["Vertical pixel offset of the empowered stage text from its anchor."] = "Deslocamento vertical em pixels do texto da fase aprimorada a partir da sua âncora.",
    ["Vertical pixel offset of the overall item level label from its anchor."] = "Deslocamento vertical em pixels do rótulo geral de nível de item a partir da sua âncora.",
    ["Vertical pixel offset of the spell name from its anchor."] = "Deslocamento vertical em pixels do nome do feitiço a partir da sua âncora.",
    ["Vertical pixel offset of the text from its anchor."] = "Deslocamento vertical em pixels do texto a partir da sua âncora.",
    ["Vertical pixel offset of the time text from its anchor."] = "Deslocamento vertical em pixels do texto de tempo a partir da sua âncora.",
    ["Vertical spacing between detail rows."] = "Espaçamento vertical entre linhas de detalhes.",
    ["Vertical spacing in pixels between adjacent boss frames (used when growing Up or Down)."] = "Espaçamento vertical em pixels entre quadros de chefe adjacentes (usado ao crescer para Cima ou para Baixo).",
    ["Vertical spacing reserved for the header row. Increase if the header text is getting clipped."] = "Espaçamento vertical reservado para a linha do cabeçalho. Aumente se o texto do cabeçalho estiver sendo cortado.",
    ["Veteran Dawncrest"] = "Veterano Dawncrest",
