    ["Warning Threshold (sec)"] = "Limite de Aviso (seg)",
    ["Warning Threshold (seconds)"] = "Limite de Aviso (segundos)",
    ["Warns when your pet enters or exits combat unexpectedly."] = "Avisa quando seu mascote entra ou sai de combate inesperadamente.",
    ["Weapon Consumable"] = "Consumível de Arma",
    ["Weapon Imbue"] = "Imbuição de Arma",
    ["Weapon Oil"] = "Óleo de Arma",
    ["Weapon Rite"] = "Rito de Arma",
    ["Weapon oil, stone, or enchant consumable used by the QUI_Weapon macro."] = "Óleo de arma, pedra ou consumível de encantamento usado pela macro QUI_Weapon.",
    ["Weeklies"] = "Semanais",
    ["Weekly Reset"] = "Reinício Semanal",
    ["Weekly Rewards / Great Vault (Req. Reload)"] = "Recompensas Semanais / Cofre Grande (Req. Recarregar)",
    ["Weighted Boomshots (AoE Fire, ranged)"] = "Tiros Pesados Explosivos (Fogo AoE, à distância)",
    ["Weightstone (AP, blunt)"] = "Pedra de Peso (AP, contundente)",
    ["Welcome"] = "Bem-vindo",
    ["Welcome to QUI"] = "Bem-vindo ao QUI",
    ["What happens to bars when the tracked buff is not active: always show, fade to the alpha below, or hide entirely."] = "O que acontece com as barras quando o bônus rastreado não está ativo: sempre mostrar, esmaecer até a transparência abaixo, ou ocultar totalmente.",
    ["What is QUI Layout Mode?"] = "O que é o Modo de Layout do QUI?",
    ["What is QUI?"] = "O que é o QUI?",
    ["What is the Cooldown Manager (CDM)?"] = "O que é o Gerenciador de Recarga (CDM)?",
    ["What the Alts datatext shows on the bar: total gold across your tracked alts, or the number of tracked alts. The tooltip always lists every alt."] = "O que o datatexto Alts mostra na barra: ouro total entre seus alts rastreados, ou o número de alts rastreados. A dica sempre lista todos os alts.",
    ["What the Alts datatext shows on the bar: total gold across your tracked alts, or the number of tracked alts. The tooltip always lists every alt. Applies everywhere the Alts datatext is shown, including datatext panels."] = "O que o datatexto Alts mostra na barra: ouro total entre seus alts rastreados, ou o número de alts rastreados. A dica sempre lista todos os alts. Aplica-se em todos os lugares onde o datatexto Alts é exibido, incluindo painéis de datatexto.",
    ["What the alert is anchored to: the screen, the CDM Essential bar, or your focus unit frame."] = "A que o alerta fica preso: à tela, à barra Essencial do CDM ou à sua moldura de unidade de foco.",
    ["What this binding does: cast a spell or macro, change target/focus/assist, open the unit menu, or send a ping. Spell and Macro reveal an input below for the spell name or macro body."] = "O que este atalho faz: conjurar um feitiço ou macro, mudar alvo/foco/assistir, abrir o menu da unidade ou enviar um ping. Feitiço e Macro exibem uma entrada abaixo para o nome do feitiço ou o corpo da macro.",
    ["What's New"] = "Novidades",
    ["When Blizzard would open a whisper in a new window (right-click popout, or the 'open whispers in a new window' setting), open a QUI conversation tab instead."] = "Quando o Blizzard abriria um sussurro em uma nova janela (pop-out com clique direito, ou a configuração de abrir sussurros em uma nova janela), abra uma aba de conversa do QUI em vez disso.",
    ["When ON (default), Healing Done / HPS sum each source's healing AND absorb shields. Turn off for pure HealingDone (matching Blizzard's stock meter)."] = "Quando ATIVADO (padrão), Healing Done / HPS somam a cura E os escudos de absorção de cada fonte. Desative para HealingDone puro (igual ao medidor padrão da Blizzard).",
    ["When ON (default), clear all damage-meter sessions when a Mythic+ key starts so Overall begins at zero for that run."] = "Quando ATIVADO (padrão), limpa todas as sessões do medidor de dano quando uma chave Mítica+ começa, para que o Total Geral comece em zero nessa rodada.",
    ["When ON (default), hide realm names: show \"Name\" instead of \"Name-Realm\" for cross-realm players on rows, tooltips, and the breakdown popup."] = "Quando ATIVADO (padrão), oculta nomes de reino: mostra \"Nome\" em vez de \"Nome-Reino\" para jogadores de outros reinos em linhas, dicas e no pop-up de detalhamento.",
    ["When ON (default), rows show the other metric in parentheses — e.g. DPS mode shows 1.5M (42.3M). Turn off to show only the primary value."] = "Quando ATIVADO (padrão), as linhas mostram a outra métrica entre parênteses - por exemplo, o modo DPS mostra 1.5M (42.3M). Desative para mostrar só o valor principal.",
    ["When ON, windows showing Overall switch to Current when a key starts, then Current switches back to Overall when the key completes."] = "Quando as janelas que mostram Total Geral alternam para Atual quando uma chave começa, e então Atual volta para Total Geral quando a chave termina.",
    ["When Swap to Primary Position is active, also hide the primary power bar so both resources aren't shown together."] = "Quando Trocar para a Posição Principal estiver ativo, também oculte a barra de poder principal para que ambos os recursos não apareçam juntos.",
    ["When an NPC gossip has a single option, pick it automatically so you skip the popup."] = "Quando um diálogo de NPC tiver uma única opção, escolha-a automaticamente para você pular a janela.",
    ["When an external button-skinning addon is installed, let it skin QUI's action buttons instead of QUI's built-in skin."] = "Com um addon externo de skin de botões instalado, permita que ele aplique skin nos botões de ação do QUI em vez da skin embutida do QUI.",
    ["When an external button-skinning addon is installed, let it skin buff/debuff icons instead of QUI's own border."] = "Com um addon externo de skin de botões instalado, permita que ele aplique skin nos ícones de buff/debuff em vez da borda do QUI.",
    ["When an external button-skinning addon is installed, let it skin group-frame aura icons instead of QUI's own border."] = "Com um addon externo de skin de botões instalado, permita que ele aplique skin nos ícones de aura do quadro de grupo em vez da borda do QUI.",
    ["When bars appear: always, only while the tracked buff/debuff is active, or only while in combat."] = "Quando as barras aparecem: sempre, apenas enquanto o bônus/debuff rastreado está ativo, ou apenas em combate.",
    ["When class color is off, use QUI accent color. Otherwise the custom Bar Color below is used."] = "Quando a cor de classe estiver desativada, use a cor de destaque do QUI. Caso contrário, usa a Cor da Barra personalizada abaixo.",
    ["When enabled, the macro selections below are stored per-character instead of being shared by every character on this AceDB profile. The toggle itself is always per-character. Turning it on copies your current profile selections as a starting point."] = "Quando ativado, as seleções de macro abaixo são armazenadas por personagem em vez de serem compartilhadas por todos os personagens neste perfil AceDB. O próprio alternador é sempre por personagem. Ativá-lo copia as seleções atuais do seu perfil como ponto de partida.",
    ["When hovering a dead unit, any spell binding is temporarily replaced by your class's resurrection spell if you know one. Restores the original spell when the unit is alive."] = "Ao passar o mouse sobre uma unidade morta, qualquer atalho de feitiço é temporariamente substituído pelo feitiço de ressurreição da sua classe, se você conhecer um. Restaura o feitiço original quando a unidade estiver viva.",
    ["When icons appear: always visible, only while the spell is active/on cooldown, or only while in combat."] = "Quando os ícones aparecem: sempre visíveis, apenas enquanto o feitiço está ativo/em recarga, ou apenas em combate.",
    ["When icons appear: always, only when the buff is active, or only while in combat."] = "Quando os ícones aparecem: sempre, apenas quando o bônus está ativo, ou apenas em combate.",
    ["When on, %s messages use the days slider on the right instead of the default retention. When off, the default applies."] = "Quando ativado, as mensagens %s usam o controle deslizante de dias à direita em vez da retenção padrão. Quando desativado, o padrão se aplica.",
    ["When on, dragging only works while holding the move modifier. When off, any plain left-click drag repositions supported windows."] = "Quando ativado, arrastar só funciona enquanto você segura o modificador de mover. Quando desativado, qualquer arrastar simples com o botão esquerdo reposiciona as janelas compatíveis.",
    ["When recalling a message with Up/Down, also restore its original chat type (Say, Yell, Whisper target, channel) so pressing Enter sends to the same destination."] = "Ao recuperar uma mensagem com Cima/Baixo, restaura também o tipo original de chat (Falar, Gritar, alvo do Sussurro, canal) para que pressionar Enter envie ao mesmo destino.",
    ["When remaining duration drops below this, the bar switches to the Low-Time Color."] = "Quando a duração restante cair abaixo disso, a barra muda para a Cor de Pouco Tempo.",
    ["When the anchor target is hidden but this frame stays visible, keep it at its last screen position instead of snapping toward the hidden anchor."] = "Quando o alvo da ancoragem estiver oculto, mas esta moldura continuar visível, mantenha-a na última posição na tela em vez de puxá-la para o alvo oculto.",
    ["When the native meter is visible. Always = shown at all times; In Combat = only during combat; Hidden = meter exists but is invisible."] = "Quando o medidor nativo estiver visível. Sempre = mostrado o tempo todo; Em Combate = apenas durante o combate; Oculto = o medidor existe, mas fica invisível.",
    ["When the primary power bar is visible (always, in combat only, when depleted, etc.)."] = "Quando a barra de poder principal estiver visível (sempre, apenas em combate, quando esgotada, etc.).",
    ["When the secondary power bar is visible (always, in combat only, when depleted, etc.)."] = "Quando a barra de poder secundária estiver visível (sempre, apenas em combate, quando esgotada, etc.).",
    ["When the secondary resource is dominant for your spec, swap it into the primary bar's position for that spec."] = "Quando o recurso secundário for o dominante para sua especialização, troque-o para a posição da barra principal dessa especialização.",
    ["When the skyriding bar is shown: always on, only while flying, or auto-fade out shortly after you land."] = "Quando a barra de montaria voadora for mostrada: sempre ligada, apenas enquanto estiver voando, ou desvanecer automaticamente pouco depois de pousar.",
    ["When to show the icon: always visible, only in combat, or only when you have a hostile target."] = "Quando mostrar o ícone: sempre visível, apenas em combate, ou apenas quando você tiver um alvo hostil.",
    ["When to show tooltips for items in your bags and equipment. Modifier options only show the tooltip while the key is held."] = "Quando mostrar dicas para itens na sua bolsa e equipamento. As opções de modificador mostram a dica apenas enquanto a tecla estiver pressionada.",
    ["When to show tooltips for spells and abilities. Modifier options only show the tooltip while the key is held."] = "Quando mostrar dicas para feitiços e habilidades. As opções de modificador mostram a dica apenas enquanto a tecla estiver pressionada.",
    ["When to show tooltips for units (NPCs and players). Modifier options only show the tooltip while the key is held."] = "Quando mostrar dicas para unidades (NPCs e jogadores). As opções de modificador mostram a dica apenas enquanto a tecla estiver pressionada.",
    ["When to show tooltips on QUI Cooldown Manager icons."] = "Quando mostrar dicas nos ícones do Gerenciador de Recarga do QUI.",
    ["When to show tooltips on QUI custom item/spell trackers."] = "Quando mostrar dicas nos rastreadores personalizados de itens/feitiços do QUI.",
    ["When to show tooltips on UI frames (action bars, unit frames, etc.)."] = "Quando mostrar dicas em molduras da interface (barras de ação, molduras de unidade, etc.).",
    ["When your character name contains a space (e.g., 'Foo Bar'), trigger on the first part. Most player names don't have spaces."] = "Quando o nome do seu personagem contém um espaço (ex.: 'Foo Bar'), acione a primeira parte. A maioria dos nomes de jogador não tem espaços.",
    ["Where global skin borders get their color: Theme (follows your theme accent), Class (your class color), or Custom (the color picker)."] = "De onde as bordas globais da skin obtêm sua cor: Tema (segue a cor de destaque do seu tema), Classe (cor da sua classe) ou Personalizada (o seletor de cor).",
    ["Where on the frame the %1$s indicator is anchored. X/Y Offset below nudges it from this anchor point."] = "Onde na moldura o indicador %1$s fica ancorado. O Deslocamento X/Y abaixo o desloca a partir deste ponto de ancoragem.",
    ["Where on the frame the bar is anchored."] = "Onde na moldura a barra fica ancorada.",
    ["Where on the frame the classification icon is anchored."] = "Onde na moldura o ícone de classificação fica ancorado.",
    ["Where on the frame the defensive icon strip is anchored. X/Y Offset below nudges it from this anchor point."] = "Onde na moldura a faixa de ícones defensivos fica ancorada. O Deslocamento X/Y abaixo a desloca a partir deste ponto de ancoragem.",
    ["Where on the frame the first private aura icon is anchored. X/Y Offset below nudges it from this anchor point."] = "Onde na moldura o primeiro ícone de aura privada fica ancorado. O Deslocamento X/Y abaixo o desloca a partir deste ponto de ancoragem.",
    ["Where on the frame the first private-aura icon is anchored."] = "Onde na moldura o primeiro ícone de aura privada fica ancorado.",
    ["Where on the frame the health text is anchored. X/Y Offset below nudges it from this anchor point."] = "Onde na moldura o texto de vida fica ancorado. O Deslocamento X/Y abaixo o desloca a partir deste ponto de ancoragem.",
    ["Where on the frame the leader/assistant icon is anchored."] = "Onde na moldura o ícone de líder/assistente fica ancorado.",
    ["Where on the frame the name text is anchored. X/Y Offset below nudges it from this anchor point."] = "Onde na moldura o texto do nome fica ancorado. O Deslocamento X/Y abaixo o desloca a partir deste ponto de ancoragem.",
    ["Where on the frame the power text is anchored. X/Y Offset below nudges it from this anchor point."] = "Onde na moldura o texto de poder fica ancorado. O Deslocamento X/Y abaixo o desloca a partir deste ponto de ancoragem.",
    ["Where on the frame the raid target icon is anchored."] = "Onde na moldura o ícone de alvo de raid fica ancorado.",
    ["Where on the frame the role icon is anchored. X/Y Offset below nudges it from this anchor point."] = "Onde na moldura o ícone de função fica ancorado. O Deslocamento X/Y abaixo o desloca a partir deste ponto de ancoragem.",
    ["Where on the frame the square is anchored."] = "Onde na moldura o quadrado fica ancorado.",
    ["Where on the frame this element is anchored. X/Y Offset below nudges it from this anchor point."] = "Onde na moldura este elemento fica ancorado. O Deslocamento X/Y abaixo o desloca a partir deste ponto de ancoragem.",
    ["Where on the player frame the combat icon is anchored."] = "Onde na moldura do jogador o ícone de combate fica ancorado.",
    ["Where on the player frame the rested icon is anchored."] = "Onde na moldura do jogador o ícone de descanso fica ancorado.",
    ["Where on the player frame the stance/form text is anchored."] = "Onde na moldura do jogador o texto de postura/forma fica ancorado.",
    ["Where pet frames are anchored relative to the group."] = "Onde as molduras do mascote são ancoradas em relação ao grupo.",
    ["Where proc / spell-activation glows come from."] = "Origem dos brilhos de proc / ativação de magia.",
    ["Where the button bar attaches relative to the chat frame. outside_left/outside_right anchor outside the chat frame's edge; inside_left/inside_right anchor inside above the scrollback; inside_tabs lays buttons horizontally next to this chat frame's tab."] = "Onde a barra de botões se fixa em relação à moldura do chat. outside_left/outside_right ancoram fora da borda da moldura do chat; inside_left/inside_right ancoram dentro, acima do histórico; inside_tabs coloca os botões horizontalmente ao lado da aba desta moldura de chat.",
    ["Where the cast icon border gets its color: Inherit (global skin border), Theme accent, Class color, or a Custom color."] = "De onde a borda do ícone de conjuração obtém sua cor: Herdar (borda global da skin), destaque do Tema, cor da Classe ou uma cor Personalizada.",
    ["Where the castbar outline gets its color: Inherit (global skin border), Theme accent, Class color, or a Custom color."] = "De onde o contorno da barra de conjuração obtém sua cor: Herdar (borda global da skin), destaque do Tema, cor da Classe ou uma cor Personalizada.",
    ["Where the current empowered stage number is anchored on the castbar."] = "Onde o número do estágio fortalecido atual fica ancorado na barra de conjuração.",
    ["Where the forces bar / text is inserted relative to the timer bars and objective rows."] = "Onde a barra/texto de forças é inserida em relação às barras de tempo e às linhas de objetivo.",
    ["Where the frame border gets its color: Inherit (global skin border), Theme accent, Class color, or Custom."] = "Origem da cor da borda do quadro: Herdar (borda de skin global), Destaque do tema, Cor de classe ou Personalizado.",
    ["Where the per-source spell breakdown popup appears when you click a row."] = "Onde o pop-up de detalhamento por fonte de feitiço aparece quando você clica em uma linha.",
    ["Where the portrait ring gets its color: Inherit (global skin border), Theme accent, Class color, or a Custom color."] = "De onde o anel do retrato obtém sua cor: Herdar (borda global da skin), destaque do Tema, cor da Classe ou uma cor Personalizada.",
    ["Where the tick timings come from. Auto tries QUI's static table first, then live calibration."] = "De onde vêm os tempos dos ticks. Auto tenta primeiro a tabela estática do QUI, depois a calibração ao vivo.",
    ["Where tick marks are drawn. Thirds matches prey stages; Quarters is purely visual."] = "Onde as marcas de tempo são desenhadas. Terços corresponde aos estágios da presa; Quartos é puramente visual.",
    ["Whether the Time datatext shows your local system time or realm server time."] = "Se o datatext Hora mostra a hora local do sistema ou a hora do servidor do reino.",
    ["Whether the bar drains horizontally or vertically as the aura ticks down."] = "Se a barra esvazia horizontalmente ou verticalmente à medida que a aura expira.",
    ["Whether the detail rows stack above or below the bar. Auto picks based on where the frame is anchored on screen."] = "Se as linhas de detalhes ficam acima ou abaixo da barra. Auto escolhe com base em onde a moldura está ancorada na tela.",
    ["Whether this binding fires on a mouse button (including scroll) or on a keyboard key pressed while hovering a unit frame."] = "Se este atalho dispara em um botão do mouse (incluindo rolagem) ou em uma tecla de teclado pressionada enquanto o cursor está sobre uma moldura de unidade.",
    ["Whether this container's rows flow horizontally or vertically."] = "Se as linhas deste contêiner fluem horizontalmente ou verticalmente.",
    ["Whether this strip shows helpful buffs or harmful debuffs."] = "Se esta faixa mostra bônus úteis ou penalidades nocivas.",
    ["Whether tracked spells stack vertically or extend horizontally."] = "Se os feitiços rastreados se empilham verticalmente ou se estendem horizontalmente.",
    ["Whetstone (AP, bladed)"] = "Pedra de Amolar (AP, cortante)",
    ["Which LibCustomGlow style to render. Pixel/Autocast support line count and thickness; Button/Flash/Hammer ignore those controls."] = "Qual estilo do LibCustomGlow renderizar. Pixel/Autocast suportam contagem de linhas e espessura; Button/Flash/Hammer ignoram esses controles.",
    ["Which LibCustomGlow style to use for the post-cast highlight."] = "Qual estilo do LibCustomGlow usar para o destaque pós-conjuração.",
    ["Which LibCustomGlow style to use while the entry is active."] = "Qual estilo do LibCustomGlow usar enquanto a entrada estiver ativa.",
    ["Which augment rune the QUI augment macro resolves to on this character."] = "Qual runa de aprimoramento a macro QUI augment resolve para este personagem.",
    ["Which chat window auto-created conversation tabs open in."] = "Em qual janela de chat as abas de conversa criadas automaticamente abrem.",
    ["Which combat potion the QUI potion macro resolves to on this character."] = "Qual poção de combate a macro QUI potion resolve para este personagem.",
    ["Which corner of each button the keybind text is anchored to."] = "Em qual canto de cada botão o texto de atalho é ancorado.",
    ["Which corner of each button the macro name is anchored to."] = "Em qual canto de cada botão o nome da macro é ancorado.",
    ["Which corner of each button the stack count is anchored to."] = "Em qual canto de cada botão a contagem de pilha é ancorada.",
    ["Which corner of each icon the keybind text is anchored to."] = "Em qual canto de cada ícone o texto do atalho fica ancorado.",
    ["Which corner of the %1$s icon the stack count is anchored to."] = "Em qual canto do ícone %1$s o contador de pilhas fica ancorado.",
    ["Which corner of the frame the first %1$s icon is anchored to."] = "Em qual canto da moldura o primeiro ícone %1$s fica ancorado.",
    ["Which corner of the icon the duration text is anchored to."] = "Em qual canto do ícone o texto da duração fica ancorado.",
    ["Which corner of the icon the keybind text is anchored to."] = "Em qual canto do ícone o texto do atalho fica ancorado.",
    ["Which corner of the icon the stack count is anchored to."] = "Em qual canto do ícone o contador de pilhas fica ancorado.",
    ["Which corner of the minimap the dungeon eye icon is anchored to."] = "Em qual canto do minimapa o ícone do olho da masmorra fica ancorado.",
    ["Which corner of the tooltip is pinned to the cursor position."] = "Em qual canto da dica fica preso à posição do cursor.",
    ["Which corner or edge of "] = "Em qual canto ou borda de ",
    ["Which corner or edge of the anchor target this frame attaches to. Together with From Point, this defines how the two frames align."] = "Em qual canto ou borda do alvo de ancoragem esta moldura se fixa. Junto com From Point, isso define como as duas molduras se alinham.",
